import React, { useContext, useState } from 'react';
import { Search, User, LogIn, LogOut, Shield, PlusCircle, Users, ChevronRight } from 'lucide-react';
import { AuthContext } from '../context/authContext';
import { useNavigate } from 'react-router-dom';

const WoodQuestBoard = () => {

  // use context of logging in 
  const { currentUser } = useContext(AuthContext);
  const { id, username, picId} = currentUser;

  // if currenUser exist then isLoggedIn is true
  const [isLoggedIn, setIsLoggedIn] = useState((!!currentUser));
  const navigate = useNavigate();

  const handleLoginClick = navigate("/login")

  const partyList = [
    { id: 1, name: "Party 01", members: "4/4", status: "Active" },
    { id: 2, name: "Party 02", members: "2/4", status: "Idle" },
    { id: 3, name: "Party 03", members: "3/4", status: "In Quest" },
    { id: 4, name: "Party 04", members: "1/4", status: "Recruiting" },
  ];

  const [quests] = useState([
    { id: 1, author: "Geralt_of_Rivia", title: "Griffin Menace at White Orchard", reward: "500 Gold", difficulty: "Medium", rotation: "-1deg" },
    { id: 2, author: "Link_HY", title: "Collect 500 Rupees for Shield Repair", reward: "Hylian Shield", difficulty: "Easy", rotation: "2deg" },
    { id: 3, author: "Cloud_S", title: "Mako Reactor Maintenance", reward: "2000 Gil", difficulty: "Hard", rotation: "-2deg" },
    { id: 4, author: "Arthur_M", title: "Train Robbery Assistance", reward: "150 Gold", difficulty: "Medium", rotation: "1.5deg" },
    { id: 5, author: "Slayer_G", title: "Goblin Den Clearing", reward: "Small Pouch", difficulty: "Easy", rotation: "-1.2deg" },
  ]);

  return (
    <div className="min-h-screen bg-[#3d2b1f]/60 font-serif text-[#4a3728] backdrop-blur-[2px]">
      
      {/* HEADER: Mahogany Banner (Semi-Transparent) */}
      <header className="sticky top-0 z-20 flex items-center justify-between bg-[#5d4037]/90 backdrop-blur-md border-b-8 border-[#3e2723] px-10 py-6 shadow-2xl">
        <div className="flex items-center space-x-6">
            {/* The Avatar Circle */}
            <div className="h-14 w-14 overflow-hidden rounded-full border-4 border-[#d7ccc8] bg-[#8d6e63] flex items-center justify-center text-[#f5f5f5] shadow-inner">
              {isLoggedIn && picId ? (
                <img 
                  src="https://cdn.pixabay.com/photo/2015/04/19/08/32/flower-729510_1280.jpg"
                  className="h-full w-full object-cover" 
                />
              ) : (
                <User size={32} /> 
              )}
            </div>
            {/* The Username Section */}
          <div>
            <p className="text-xs uppercase tracking-widest text-[#d7ccc8] opacity-70">Adventurer Rank</p>
            <span className="font-bold text-[#f5f5f5] text-xl tracking-wide">
              {isLoggedIn ? username : "Guest_Traveler"}
            </span>
          </div>
        </div>

        <div className="text-center absolute left-1/2 -translate-x-1/2 text-[#d7ccc8]">
          <h1 className="text-5xl font-black uppercase tracking-[0.2em] drop-shadow-[0_5px_5px_rgba(0,0,0,0.5)]">
            The Guild Board
          </h1>
        </div>

        <div className="flex items-center space-x-4">
          <button 
            onClick={handleLoginClick}
            className="flex items-center space-x-2 rounded bg-[#a1887f] px-6 py-2 font-bold text-[#3e2723] hover:scale-105 transition-transform border-b-4 border-[#3e2723]"
          >
            {isLoggedIn ? <><LogOut size={20} /><span>Sign Out</span></> : <><LogIn size={20} /><span>Sign In</span></>}
          </button>
        </div>
      </header>

      {/* MAIN LAYOUT */}
      <div className="flex max-w-[1600px] mx-auto p-10 gap-10">
        
        {/* LEFT COLUMN */}
        <aside className="w-80 space-y-6 sticky top-32 h-fit">
          
          {/* SEARCH (Semi-Transparent) */}
          <div className="bg-[#efebe9]/80 backdrop-blur-sm p-6 rounded shadow-lg border-2 border-[#8d6e63] relative">
            <div className="absolute -top-3 -left-3 bg-[#5d4037] text-white p-2 rounded shadow-md">
              <Search size={20} />
            </div>
            <h3 className="font-bold uppercase mb-4 text-[#3e2723] border-b border-[#d7ccc8] pb-2 text-sm tracking-widest">Search Scrolls</h3>
            <input
              type="text"
              className="w-full bg-transparent border-b-2 border-[#8d6e63] focus:outline-none italic text-[#5d4037] placeholder-[#8d6e63]/60"
              placeholder="Keywords..."
            />
          </div>

          {/* MANAGEMENT NAV (Semi-Transparent) */}
          <nav className="bg-[#f5f5dc]/80 backdrop-blur-sm p-6 rounded shadow-lg border-2 border-[#8d6e63] space-y-4">
            <h3 className="font-bold uppercase text-[#3e2723] text-xs opacity-60 tracking-widest">Guild Parties</h3>
            
            <div className="space-y-3">
              {partyList.map((party) => (
                <a 
                  key={party.id}
                  href={`/party/${party.id}`} 
                  className="flex items-center justify-between group bg-[#d7ccc8]/40 p-3 rounded border border-[#8d6e63]/30 hover:bg-[#5d4037] hover:text-white transition-all duration-200"
                >
                  <div className="flex items-center gap-3">
                    <Users size={18} className="opacity-70 group-hover:opacity-100" />
                    <div>
                      <p className="font-black uppercase text-sm tracking-tight leading-none">{party.name}</p>
                      <p className="text-[10px] uppercase opacity-60 group-hover:text-[#d7ccc8]">{party.status}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] font-bold bg-[#8d6e63]/80 group-hover:bg-[#a1887f] text-white px-2 py-0.5 rounded shadow-inner transition-colors">
                      {party.members}
                    </span>
                    <ChevronRight size={14} className="opacity-0 group-hover:opacity-100 -translate-x-2 group-hover:translate-x-0 transition-all" />
                  </div>
                </a>
              ))}
            </div>

            <hr className="border-[#d7ccc8]/50 my-4" />

            <div>
              <button className="w-full flex items-center justify-center gap-2 bg-[#8d6e63]/90 py-4 rounded text-[#f5f5dc] font-black uppercase tracking-tighter hover:bg-[#3e2723] transition-all shadow-md border-b-4 border-[#3e2723] active:border-b-0 active:translate-y-1 backdrop-blur-sm">
                <PlusCircle size={20} />
                Post a Bounty
              </button>
            </div>
          </nav>
        </aside>

        {/* RIGHT COLUMN: The Board Grid */}
        <main className="flex-1">
          <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-8">
            {quests.map((quest) => (
              <div 
                key={quest.id} 
                className="group relative p-8 shadow-[10px_10px_20px_rgba(0,0,0,0.3)] hover:shadow-[15px_15px_30px_rgba(0,0,0,0.4)] transition-all duration-300 hover:-translate-y-2 rounded-sm border border-white/10"
                style={{ 
                  transform: `rotate(${quest.rotation})`,
                  backgroundImage: 'url("https://www.transparenttextures.com/patterns/paper-fibers.png")',
                  backgroundColor: 'rgba(253, 246, 227, 0.85)', // Semi-transparent parchment
                  backdropFilter: 'blur(4px)'
                }}
              >
                <div className="absolute top-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-red-800/90 rounded-full shadow-inner border-2 border-red-950 z-10"></div>
                
                <div className="absolute -right-4 -top-4 opacity-5 text-[#3e2723]">
                  <Shield size={140} />
                </div>

                <div className="flex justify-between items-center mb-6 border-b-2 border-dashed border-[#d7ccc8] pb-4">
                  <span className="text-xs font-black bg-[#5d4037]/90 text-[#f5f5f5] px-2 py-1 rounded tracking-tighter shadow-sm">
                    {quest.difficulty}
                  </span>
                  <span className="text-xl font-black text-[#5d4037] drop-shadow-sm">
                    {quest.reward}
                  </span>
                </div>

                <h2 className="mb-4 text-2xl font-extrabold text-[#3e2723] leading-tight uppercase min-h-[4rem]">
                  {quest.title}
                </h2>
                
                <p className="text-sm italic text-[#6d4c41] mb-8">
                  Client: <span className="font-bold not-italic text-[#3e2723] underline decoration-wavy">{quest.author}</span>
                </p>

                <div className="flex flex-col space-y-2">
                  <button className="w-full bg-[#5d4037]/90 py-3 text-sm font-bold text-[#f5f5f5] hover:bg-[#3e2723] shadow-md active:translate-y-1 transition-all">
                    ACCEPT CONTRACT
                  </button>
                  <button className="w-full border-2 border-[#5d4037]/50 py-2 text-xs font-bold text-[#5d4037] hover:bg-white/30 hover:border-[#5d4037] transition-all">
                    VIEW DETAILS
                  </button>
                </div>
              </div>
            ))}
          </div>
        </main>
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        body {
          background-image: url('https://images.alphacoders.com/110/1105802.jpg');
          background-size: cover;
          background-attachment: fixed;
          background-repeat: no-repeat;
          background-position: center;
          background-color: #1a0f0a; /* Fallback */
        }
        ::-webkit-scrollbar { width: 12px; }
        ::-webkit-scrollbar-track { background: rgba(61, 43, 31, 0.5); }
        ::-webkit-scrollbar-thumb { background: #5d4037; border: 3px solid transparent; background-clip: padding-box; border-radius: 10px; }
      `}} />
    </div>
  );
};

export default WoodQuestBoard;
